#!/usr/bin/env python3
"""Heuristic exploration planner with utility greedy + global BFS planning.
Robust version with cycle avoidance and epsilon-greedy exploration."""
import os
import sys
import json
import argparse
import math
import random
from collections import deque

import numpy as np
from cogniplan_env import ExplorationEnv


def euclidean(a, b):
    return math.hypot(a[0] - b[0], a[1] - b[1])


class HeuristicPlanner:
    def __init__(self, epsilon=0.05, tabu_len=5):
        self.epsilon = epsilon
        self.tabu_len = tabu_len
        self.adj = []
        self.coord_to_idx = {}
        self.n_nodes = 0
        self.node_coords = []

    def reset_episode(self, nodes):
        """Build graph from initial node list."""
        self.n_nodes = len(nodes)
        self.coord_to_idx = {}
        self.node_coords = []
        for i, nd in enumerate(nodes):
            x, y = float(nd['coords'][0]), float(nd['coords'][1])
            self.coord_to_idx[(x, y)] = i
            self.node_coords.append((x, y))
        # adjacency from nodes' neighbors field
        self.adj = [[] for _ in range(self.n_nodes)]
        for i, nd in enumerate(nodes):
            for nb in nd.get('neighbors', []):
                key = (float(nb[0]), float(nb[1]))
                if key in self.coord_to_idx:
                    self.adj[i].append(self.coord_to_idx[key])
        # ensure symmetry (not strictly necessary but safe)
        for i in range(self.n_nodes):
            for j in self.adj[i]:
                if i not in self.adj[j]:
                    self.adj[j].append(i)

    def find_closest_node(self, pos):
        best = -1
        best_d = float('inf')
        for coord, idx in self.coord_to_idx.items():
            d = euclidean(coord, pos)
            if d < best_d:
                best_d = d
                best = idx
        return best

    def bfs_path(self, start_idx, target_idx):
        """Returns (dist, parent) arrays; parent[i]=predecessor, -1 if unreachable."""
        if start_idx < 0 or target_idx < 0 or start_idx >= self.n_nodes or target_idx >= self.n_nodes:
            return None, None
        adj = self.adj
        n = self.n_nodes
        dist = [-1] * n
        parent = [-1] * n
        q = deque([start_idx])
        dist[start_idx] = 0
        while q:
            u = q.popleft()
            if u == target_idx:
                break
            for v in adj[u]:
                if dist[v] == -1:
                    dist[v] = dist[u] + 1
                    parent[v] = u
                    q.append(v)
        return dist, parent

    def reconstruct_path(self, start_idx, target_idx, parent):
        """Return node index list from start to target (excluding start)."""
        if parent is None or start_idx < 0 or target_idx < 0 or target_idx >= len(parent):
            return []
        path = []
        curr = target_idx
        # safety iteration limit
        for _ in range(self.n_nodes + 1):
            if curr < 0 or curr >= len(parent):
                break
            if curr == start_idx:
                break
            path.append(curr)
            prev = parent[curr]
            if prev < 0 or prev >= len(parent):
                break
            curr = prev
        else:
            # loop too long
            return []
        if not path:
            return []
        if curr == start_idx:
            path.reverse()
            return path
        else:
            # did not reach start
            return []

    def select_action(self, obs, curr_idx, step, visited_recent):
        """Choose next node index to move to. Returns -1 if episode should end."""
        neighbor_coords = obs.get('neighbors', [])
        if not neighbor_coords:
            return -1
        # map neighbors to indices
        neighbor_idxs = []
        for nb in neighbor_coords:
            key = (float(nb[0]), float(nb[1]))
            if key in self.coord_to_idx:
                neighbor_idxs.append(self.coord_to_idx[key])
        if not neighbor_idxs:
            return -1

        utilities = [n['utility'] for n in obs['nodes']]
        # ensure length matches
        if len(utilities) != self.n_nodes:
            # mismatch -> fallback: random neighbor
            return random.choice(neighbor_idxs)

        # 1) Greedy: highest utility neighbor > 0, not recently visited
        best_util = -1
        best_nb = -1
        for ni in neighbor_idxs:
            if ni in visited_recent:
                continue
            if utilities[ni] > best_util:
                best_util = utilities[ni]
                best_nb = ni
        if best_util > 0 and best_nb >= 0:
            return best_nb

        # 2) epsilon-random among neighbors (avoid recent)
        if random.random() < self.epsilon:
            valid = [ni for ni in neighbor_idxs if ni not in visited_recent]
            if not valid:
                valid = neighbor_idxs
            return random.choice(valid)

        # 3) Global BFS to highest utility node > 0
        max_util = -1
        global_best = -1
        for i, u in enumerate(utilities):
            if u > max_util:
                max_util = u
                global_best = i
        if max_util <= 0 or global_best < 0:
            # no frontiers left, end episode
            return -1

        if global_best == curr_idx:
            # already at best, but no neighbor utility>0; move anywhere
            return random.choice(neighbor_idxs)

        # BFS to global_best
        _, parent = self.bfs_path(curr_idx, global_best)
        path = self.reconstruct_path(curr_idx, global_best, parent)
        if path:
            return path[0]
        else:
            # no path; fallback to random
            return random.choice(neighbor_idxs)


def run_episode(env, planner, max_steps=128):
    obs = env.reset()
    nodes = obs['nodes']
    planner.reset_episode(nodes)
    robot_pos = (float(obs['robot_pos'][0]), float(obs['robot_pos'][1]))
    curr_idx = planner.find_closest_node(robot_pos)
    if curr_idx < 0:
        curr_idx = 0  # fallback
    visited_recent = deque(maxlen=planner.tabu_len)
    visited_recent.append(curr_idx)

    for step in range(max_steps):
        next_idx = planner.select_action(obs, curr_idx, step, visited_recent)
        if next_idx < 0 or next_idx >= planner.n_nodes:
            break
        if next_idx not in planner.adj[curr_idx] and next_idx != curr_idx:
            # not a neighbor – safety break
            break
        # move to target node coordinates
        target_coord = planner.node_coords[next_idx]
        obs, info = env.step(target_coord)
        visited_recent.append(next_idx)
        curr_idx = next_idx
        if info.get('done', False):
            break

    metrics = env.get_metrics()
    return {
        'explored_rate': float(metrics['explored_rate']),
        'travel_distance': float(metrics['travel_distance']),
        'success': bool(metrics['success']),
        'n_steps': int(metrics['n_steps'])
    }


def evaluate(args):
    data_path = args.data_path
    output_path = args.output

    # Load eval config
    config_path = os.path.join(data_path, 'eval_config.json')
    with open(config_path, 'r') as f:
        eval_config = json.load(f)

    maps_eval_dir = os.path.join(data_path, 'maps_eval')
    env_types = ['room', 'tunnel', 'outdoor']

    per_episode = []
    per_type_success = {t: 0 for t in env_types}
    per_type_count = {t: 0 for t in env_types}
    per_type_success_dist = {t: [] for t in env_types}
    per_type_explored = {t: [] for t in env_types}

    planner = HeuristicPlanner(epsilon=0.05, tabu_len=5)

    for etype in env_types:
        subdir = os.path.join(maps_eval_dir, etype)
        if not os.path.isdir(subdir):
            continue
        map_files = sorted([
            f for f in os.listdir(subdir)
            if f.endswith('.png') or f.endswith('.pgm')
        ])
        for mf in map_files:
            map_path = os.path.join(subdir, mf)
            env = ExplorationEnv(map_path=map_path)
            res = run_episode(env, planner, max_steps=128)
            per_episode.append({
                'map_path': os.path.join(etype, mf),
                'env_type': etype,
                'success': 1 if res['success'] else 0,
                'travel_distance': res['travel_distance'],
                'explored_rate': res['explored_rate']
            })
            per_type_count[etype] += 1
            per_type_explored[etype].append(res['explored_rate'])
            if res['success']:
                per_type_success[etype] += 1
                per_type_success_dist[etype].append(res['travel_distance'])

    total_episodes = len(per_episode)
    explored_rates = [ep['explored_rate'] for ep in per_episode]
    overall_explored = float(np.mean(explored_rates)) if explored_rates else 0.0
    success_count = sum(1 for ep in per_episode if ep['success'])
    success_rate = success_count / total_episodes if total_episodes > 0 else 0.0
    # travel distance mean across successful episodes only
    all_success_distances = [ep['travel_distance'] for ep in per_episode if ep['success']]
    overall_travel = float(np.mean(all_success_distances)) if all_success_distances else 0.0

    per_type = {}
    for etype in env_types:
        cnt = per_type_count[etype]
        if cnt == 0:
            per_type[etype] = {
                'explored_rate': 0.0,
                'travel_distance': 0.0,
                'success_rate': 0.0
            }
        else:
            succ = per_type_success[etype]
            per_type[etype] = {
                'explored_rate': float(np.mean(per_type_explored[etype])),
                'travel_distance': float(np.mean(per_type_success_dist[etype])) if per_type_success_dist[etype] else 0.0,
                'success_rate': succ / cnt
            }

    output = {
        'explored_rate': overall_explored,
        'travel_distance': overall_travel,
        'success_rate': success_rate,
        'per_episode': per_episode,
        'per_type': per_type,
        'total_episodes': total_episodes
    }
    with open(output_path, 'w') as f:
        json.dump(output, f, indent=2)
    print(f"Evaluation complete. {success_count}/{total_episodes} succeeded.")


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', type=str, required=True)
    parser.add_argument('--checkpoint', type=str, required=True)
    parser.add_argument('--output', type=str, required=True)
    args = parser.parse_args()
    evaluate(args)


if __name__ == '__main__':
    main()
